import { BedrockAgentRuntimeClient, InvokeAgentCommand } from '@aws-sdk/client-bedrock-agent-runtime';

const client = new BedrockAgentRuntimeClient({ region: 'us-east-1' });

interface EmailAgentResponse {
  to: string;
  subject: string;
  body: string;
  status: string;
}

export async function invokeEmailAgent(input: string, sessionId: string = 'email-session'): Promise<EmailAgentResponse> {
  const command = new InvokeAgentCommand({
    agentId: 'YOUR_AGENT_ID',
    agentAliasId: 'YOUR_AGENT_ALIAS_ID',
    sessionId,
    inputText: input
  });

  const response = await client.send(command);
  let completion = '';

  for await (const event of response.completion!) {
    if (event.chunk?.bytes) {
      completion += Buffer.from(event.chunk.bytes).toString();
    }
  }

  return JSON.parse(completion) as EmailAgentResponse;
}

import boto3

kb_client = boto3.client('bedrock-agent-runtime')

def retrieve_email_templates(query: str, kb_id: str):
    response = kb_client.retrieve(
        knowledgeBaseId=kb_id,
        retrievalQuery={
            'text': query
        },
        retrievalConfiguration={
            'vectorSearchConfiguration': {
                'numberOfResults': 5
            }
        }
    )

    return [
        {
            'content': r['content']['text'],
            'metadata': r['metadata'],
            'score': r['score']
        }
        for r in response['retrievalResults']
    ]

# Usage
templates = retrieve_email_templates('professional reply template', 'YOUR_KB_ID')

