import { verify } from 'vex-sdk';

type EmailDraft = {
  to: string;
  subject: string;
  body: string;
};

export async function verifyEmailDraft(draft: EmailDraft): Promise<boolean> {
  const result = await verify({
    input: draft,
    checks: [
      {
        type: 'pii_filter',
        fields: ['body'],
        blocklist: ['ssn', 'passport'],
        action: 'block'
      },
      {
        type: 'tone_check',
        field: 'body',
        tone: 'professional',
        minScore: 0.85
      },
      {
        type: 'confidentiality',
        field: 'body',
        keywords: ['confidential', 'internal use only'],
        requireApproval: true
      }
    ],
    riskProfile: 'high'
  });

  return result.status === 'pass';
}

